```rust,ignore
use futures::stream::{Stream, StreamExt};

/// 异步流处理
pub async fn process_stream<S>(mut stream: S) -> Vec<S::Item>
where
    S: Stream + Unpin,
{
    let mut results = Vec::new();

    while let Some(item) = stream.next().await {
        results.push(item);
    }

    results
}
```

