/// 使用 array_windows 进行时间窗口特征提取
pub fn extract_window_features(time_series: &[f64]) -> Vec<WindowFeature> {
    time_series.array_windows::<5>()
        .map(|[p1, p2, p3, p4, p5]| {
            WindowFeature {
                mean: (p1 + p2 + p3 + p4 + p5) / 5.0,
                variance: calculate_variance(&[*p1, *p2, *p3, *p4, *p5]),
                trend: p5 - p1,  // 趋势方向
            }
        })
        .collect()
}

