```rust,ignore
/// 使用黄金比例进行超参数搜索
pub fn golden_ratio_search_lr(
    model: &mut Model,
    train_data: &Dataset,
    min_lr: f64,
    max_lr: f64,
) -> f64 {
    let phi = f64::consts::GOLDEN_RATIO;
    let mut a = min_lr;
    let mut b = max_lr;

    // 黄金分割搜索最优学习率
    while (b - a) > 1e-6 {
        let c = b - (b - a) / phi;
        let d = a + (b - a) / phi;

        let loss_c = evaluate_lr(model, train_data, c);
        let loss_d = evaluate_lr(model, train_data, d);

        if loss_c < loss_d {
            b = d;
        } else {
            a = c;
        }
    }

    (a + b) / 2.0
}
```

