```rust,ignore
use axum::{
    routing::{get, post},
    Router,
    extract::State,
    http::StatusCode,
    Json,
};
use std::sync::Arc;
use tokio::sync::RwLock;
use serde::{Deserialize, Serialize};

#[derive(Clone)]
struct AppState {
    db_pool: sqlx::PgPool,
    cache: Arc<RwLock<lru::LruCache<String, String>>>,
}

async fn create_server() -> Result<(), Box<dyn std::error::Error>> {
    let state = AppState {
        db_pool: sqlx::PgPool::connect("postgres://localhost/db").await?,
        cache: Arc::new(RwLock::new(lru::LruCache::new(1000))),
    };

    let app = Router::new()
        .route("/users/:id", get(get_user))
        .route("/users", post(create_user))
        .route("/health", get(health_check))
        .with_state(state);

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await?;
    axum::serve(listener, app).await?;

    Ok(())
}

async fn get_user(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Result<Json<User>, StatusCode> {
    // 先检查缓存
    {
        let cache = state.cache.read().await;
        if let Some(user_json) = cache.get(&id) {
            if let Ok(user) = serde_json::from_str(user_json) {
                return Ok(Json(user));
            }
        }
    }

    // 查询数据库
    let user: User = sqlx::query_as("SELECT * FROM users WHERE id = $1")
        .bind(&id)
        .fetch_one(&state.db_pool)
        .await
        .map_err(|_| StatusCode::NOT_FOUND)?;

    // 更新缓存
    {
        let mut cache = state.cache.write().await;
        if let Ok(json) = serde_json::to_string(&user) {
            cache.put(id, json);
        }
    }

    Ok(Json(user))
}

#[derive(Debug, Serialize, Deserialize, sqlx::FromRow)]
struct User {
    id: String,
    name: String,
    email: String,
}

async fn health_check() -> &'static str {
    "OK"
}

async fn create_user(
    State(state): State<AppState>,
    Json(payload): Json<CreateUserRequest>,
) -> Result<Json<User>, StatusCode> {
    let user: User = sqlx::query_as(
        "INSERT INTO users (id, name, email) VALUES ($1, $2, $3) RETURNING *"
    )
    .bind(&payload.id)
    .bind(&payload.name)
    .bind(&payload.email)
    .fetch_one(&state.db_pool)
    .await
    .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok(Json(user))
}

#[derive(Deserialize)]
struct CreateUserRequest {
    id: String,
    name: String,
    email: String,
}
