```rust
// 旧接口
trait OldInterface {
    fn old_method(&self) -> String;
}

// 新接口
trait NewInterface {
    fn new_method(&self) -> String;
}

// 适配器
struct Adapter {
    old: Box<dyn OldInterface>,
}

impl NewInterface for Adapter {
    fn new_method(&self) -> String {
        self.old.old_method()
    }
}
```

#### 装饰器模式 {#装饰器模式}

> **来源: [Rust Standard Library](https://doc.rust-lang.org/std/)**
>
> **来源: [Rust Official Docs](https://doc.rust-lang.org/)**

```rust
trait Component {
    fn operation(&self) -> String;
}

struct ConcreteComponent;
impl Component for ConcreteComponent {
    fn operation(&self) -> String {
        "ConcreteComponent".to_string()
    }
}

struct Decorator {
    component: Box<dyn Component>,
}

impl Component for Decorator {
    fn operation(&self) -> String {
        format!("Decorator({})", self.component.operation())
    }
}
```

### 3. 行为型模式 {#3-行为型模式}

> **来源: [Rust RFCs](https://github.com/rust-lang/rfcs)**

#### 策略模式 {#策略模式}

> **来源: [POPL](https://www.sigplan.org/Conferences/POPL/)**

```rust
trait Strategy {
    fn execute(&self, data: &[i32]) -> i32;
}

struct SumStrategy;
impl Strategy for SumStrategy {
    fn execute(&self, data: &[i32]) -> i32 {
        data.iter().sum()
    }
}

struct MaxStrategy;
impl Strategy for MaxStrategy {
    fn execute(&self, data: &[i32]) -> i32 {
        *data.iter().max().unwrap()
    }
}

struct Context {
    strategy: Box<dyn Strategy>,
}

impl Context {
    fn new(strategy: Box<dyn Strategy>) -> Self {
        Self { strategy }
    }

    fn execute(&self, data: &[i32]) -> i32 {
        self.strategy.execute(data)
    }
}
```

#### 观察者模式 {#观察者模式}

> **来源: [IEEE](https://standards.ieee.org/)**

```rust
use std::sync::{Arc, Mutex};

trait Observer {
    fn update(&self, data: &str);
}

struct ConcreteObserver {
    name: String,
}

impl Observer for ConcreteObserver {
    fn update(&self, data: &str) {
        println!("{} 收到更新: {}", self.name, data);
    }
}

struct Subject {
    observers: Vec<Arc<dyn Observer>>,
}

impl Subject {
    fn new() -> Self {
        Self {
            observers: Vec::new(),
        }
    }

    fn attach(&mut self, observer: Arc<dyn Observer>) {
        self.observers.push(observer);
    }

    fn notify(&self, data: &str) {
        for observer in &self.observers {
            observer.update(data);
        }
    }
}
```

