impl Coffee for SimpleCoffee {
    fn cost(&self) -> f64 { 2.0 }
    fn description(&self) -> String { "简单咖啡".to_string() }
}

// 装饰器基类（泛型实现）
struct MilkDecorator<C: Coffee> {
    inner: C,
}

impl<C: Coffee> Coffee for MilkDecorator<C> {
