```rust,ignore
use core::cell::RefCell;
use cortex_m::interrupt::Mutex;

static SHARED_DATA: Mutex<RefCell<u32>> = Mutex::new(RefCell::new(0));

fn update_data(value: u32) {
    cortex_m::interrupt::free(|cs| {
        *SHARED_DATA.borrow(cs).borrow_mut() = value;
    });
}
