### 3. 构建器宏 {#3-构建器宏}

> **来源: [Wikipedia - Type System](https://en.wikipedia.org/wiki/Type_system)**

```rust,ignore
macro_rules! builder {
    ($name:ident { $($field:ident: $type:ty),* }) => {
        struct $name {
            $($field: Option<$type>),*
        }

        impl $name {
            fn new() -> Self {
                Self {
                    $($field: None),*
                }
            }

            $(
                fn $field(mut self, value: $type) -> Self {
                    self.$field = Some(value);
                    self
                }
            )*
        }
    };
}

builder!(Config {
    host: String,
    port: u16,
});

// 使用
let config = Config::new()
    .host("localhost".to_string())
    .port(8080);
```

