### 示例 1: 自定义 Derive 宏 {#示例-1-自定义-derive-宏}

> **来源: [Rustonomicon - doc.rust-lang.org/nomicon](https://doc.rust-lang.org/nomicon/)**

```rust,ignore
// lib.rs - 过程宏 crate
use proc_macro::TokenStream;
use quote::quote;
use syn::{parse_macro_input, DeriveInput, Data, Fields};

#[proc_macro_derive(Builder)]
pub fn derive_builder(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let name = &input.ident;
    let builder_name = quote::format_ident!("{}Builder", name);

    // 提取字段信息
    let fields = match &input.data {
        Data::Struct(data) => match &data.fields {
            Fields::Named(fields) => &fields.named,
            _ => panic!("只支持命名字段"),
        },
        _ => panic!("只支持 struct"),
    };

    // 生成 Builder 字段
    let builder_fields = fields.iter().map(|f| {
        let name = &f.ident;
        let ty = &f.ty;
        quote! { #name: Option<#ty> }
    });

    // 生成 setter 方法
    let setters = fields.iter().map(|f| {
        let name = &f.ident;
        let ty = &f.ty;
        quote! {
            pub fn #name(mut self, value: #ty) -> Self {
                self.#name = Some(value);
                self
            }
        }
    });

    // 生成 build 方法
    let build_fields = fields.iter().map(|f| {
        let name = &f.ident;
        quote! {
            #name: self.#name.ok_or(concat!(stringify!(#name), " 是必需的"))?
        }
    });

    let expanded = quote! {
        pub struct #builder_name {
            #(#builder_fields,)*
        }

        impl #builder_name {
            pub fn new() -> Self {
                Self {
                    #(#name: None,)*
                }
            }

            #(#setters)*

            pub fn build(self) -> Result<#name, String> {
                Ok(#name {
                    #(#build_fields,)*
                })
            }
        }

        impl #name {
            pub fn builder() -> #builder_name {
                #builder_name::new()
            }
        }
    };

    TokenStream::from(expanded)
}
```

### 示例 2: 属性宏 {#示例-2-属性宏}

> **来源: [PLDI](https://www.sigplan.org/Conferences/PLDI/)**

```rust,ignore
use proc_macro::TokenStream;
use quote::quote;
use syn::{parse_macro_input, ItemFn};

// 计时属性宏
#[proc_macro_attribute]
pub fn timed(attr: TokenStream, item: TokenStream) -> TokenStream {
    let func = parse_macro_input!(item as ItemFn);
    let func_name = &func.sig.ident;
    let func_vis = &func.vis;
    let func_block = &func.block;
    let func_sig = &func.sig;

    // 解析属性参数
    let label = if attr.is_empty() {
        func_name.to_string()
    } else {
        attr.to_string().replace('"', "")
    };

    let expanded = quote! {
        #func_vis #func_sig {
            let _start = std::time::Instant::now();
            let _result = #func_block;
            let _elapsed = _start.elapsed();
            println!("[timed] {} 耗时: {:?}", #label, _elapsed);
            _result
        }
    };

    TokenStream::from(expanded)
}

// 使用
// #[timed("自定义标签")]
// fn heavy_computation() -> i32 { ... }
```

### 示例 3: 函数式宏 {#示例-3-函数式宏}

> **来源: [Wikipedia - Memory Safety](https://en.wikipedia.org/wiki/Memory_Safety)**

```rust,ignore
use proc_macro::TokenStream;
use proc_macro2::TokenTree;
use quote::quote;

// SQL 查询验证宏
#[proc_macro]
pub fn sql(input: TokenStream) -> TokenStream {
    let tokens: Vec<_> = input.into_iter().collect();

    // 简单解析：检查是否是 SELECT/INSERT/UPDATE/DELETE
    if let Some(first) = tokens.first() {
        let sql_type = first.to_string().to_uppercase();
        let allowed = ["SELECT", "INSERT", "UPDATE", "DELETE"];

        if !allowed.contains(&sql_type.as_str()) {
            return syn::Error::new_spanned(
                first,
                "只支持 SELECT, INSERT, UPDATE, DELETE"
            )
            .to_compile_error()
            .into();
        }
    }

    // 转换回字符串
    let sql_string: String = tokens.iter()
        .map(|t| t.to_string())
        .collect::<Vec<_>>()
        .join(" ");

    let expanded = quote! {
        #sql_string
    };

    TokenStream::from(expanded)
}

// 使用
// let query = sql!(SELECT * FROM users WHERE id = 1);
```

