#### 多生产者单消费者 {#多生产者单消费者}

> **来源: [Rust Standard Library](https://doc.rust-lang.org/std/)**

```rust,ignore
use std::sync::mpsc;

let (tx, rx) = mpsc::channel();
let tx1 = tx.clone();
let tx2 = tx.clone();

thread::spawn(move || {
    tx1.send(1).unwrap();
});

thread::spawn(move || {
    tx2.send(2).unwrap();
});

drop(tx); // 关闭原始发送端

for received in rx {
    println!("收到: {}", received);
