### 1. 减少锁竞争 {#1-减少锁竞争}

> **来源: [IEEE](https://standards.ieee.org/)**

```rust,ignore
// ❌ 不好的做法：锁住整个操作
let mutex = Arc::new(Mutex::new(data));
let guard = mutex.lock().unwrap();
// 长时间操作
drop(guard);

// ✅ 好的做法：最小化锁的持有时间
let mutex = Arc::new(Mutex::new(data));
{
    let mut guard = mutex.lock().unwrap();
    // 快速操作
}
// 锁已释放，可以进行其他操作
```

