### 13.1 新类型模式 {#131-新类型模式}

> **来源: [PLDI](https://www.sigplan.org/Conferences/PLDI/)**

```rust,ignore
use std::fmt;
use std::str::FromStr;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct UserId(u64);

impl UserId {
    pub fn new(id: u64) -> Self {
        UserId(id)
    }

    pub fn as_u64(&self) -> u64 {
        self.0
    }
}

impl fmt::Display for UserId {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.0)
    }
}

impl FromStr for UserId {
    type Err = ParseError;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        s.parse::<u64>()
            .map(UserId::new)
            .map_err(|_| ParseError::new("无效的用户ID"))
    }
}
```

### 13.2 Builder 模式 {#132-builder-模式}

> **来源: [Wikipedia - Memory Safety](https://en.wikipedia.org/wiki/Memory_Safety)**

```rust,ignore
#[derive(Debug, Clone)]
pub struct Config {
    host: String,
    port: u16,
    timeout: Duration,
    retries: u32,
}

impl Config {
    pub fn builder() -> ConfigBuilder {
        ConfigBuilder::default()
    }
}

#[derive(Debug, Default)]
pub struct ConfigBuilder {
    host: Option<String>,
    port: Option<u16>,
    timeout: Option<Duration>,
    retries: Option<u32>,
}

impl ConfigBuilder {
    pub fn host(mut self, host: impl Into<String>) -> Self {
        self.host = Some(host.into());
        self
    }

    pub fn port(mut self, port: u16) -> Self {
        self.port = Some(port);
        self
    }

    pub fn timeout(mut self, timeout: Duration) -> Self {
        self.timeout = Some(timeout);
        self
    }

    pub fn retries(mut self, retries: u32) -> Self {
        self.retries = Some(retries);
        self
    }

    pub fn build(self) -> Result<Config, ConfigError> {
        Ok(Config {
            host: self.host.ok_or(ConfigError::MissingField("host"))?,
            port: self.port.unwrap_or(8080),
            timeout: self.timeout.unwrap_or(Duration::from_secs(30)),
            retries: self.retries.unwrap_or(3),
        })
    }
}

// 使用
let config = Config::builder()
    .host("localhost")
    .port(3000)
    .timeout(Duration::from_secs(60))
    .retries(5)
    .build()?;
```

### 13.3 状态机模式 {#133-状态机模式}

> **来源: [Wikipedia - Type System](https://en.wikipedia.org/wiki/Type_system)**

```rust,ignore
// 状态标记类型
pub struct Idle;
pub struct Running {
    start_time: Instant,
}
pub struct Stopped {
    duration: Duration,
}

// 状态机
pub struct StateMachine<State> {
    state: State,
}

impl StateMachine<Idle> {
    pub fn new() -> Self {
        StateMachine { state: Idle }
    }

    pub fn start(self) -> StateMachine<Running> {
        StateMachine {
            state: Running {
                start_time: Instant::now(),
            },
        }
    }
}

impl StateMachine<Running> {
    pub fn stop(self) -> StateMachine<Stopped> {
        let duration = self.state.start_time.elapsed();
        StateMachine {
            state: Stopped { duration },
        }
    }

    pub fn elapsed(&self) -> Duration {
        self.state.start_time.elapsed()
    }
}

impl StateMachine<Stopped> {
    pub fn duration(&self) -> Duration {
        self.state.duration
    }

    pub fn restart(self) -> StateMachine<Running> {
        StateMachine {
            state: Running {
                start_time: Instant::now(),
            },
        }
    }
}

// 使用
let machine = StateMachine::new();
let running = machine.start();
// ... 一些操作
let stopped = running.stop();
println!("运行时长: {:?}", stopped.duration());
```

