```rust
// HTTP 请求结构
pub struct HttpRequest {
    pub method: HttpMethod,      // GET, POST, PUT, DELETE 等
    pub uri: String,            // 请求路径
    pub version: HttpVersion,   // HTTP/1.1, HTTP/2 等
    pub headers: HashMap<String, String>, // 请求头
    pub body: Vec<u8>,          // 请求体
}

// HTTP 响应结构
pub struct HttpResponse {
    pub version: HttpVersion,   // HTTP 版本
